 -- lua/multi_context/skills/registry.lua local M = {} -- Calcula o caminho base da pasta do plugin de forma robusta local function get_plugin_base_path() -- Tenta obter o caminho do arquivo deste próprio script (registry.lua) local source = debug.getinfo(1, "S").source:sub(2) if not source then return nil end -- O caminho deve terminar em .../lua/multi_context/skills/registry.lua -- Queremos extrair .../lua/multi_context/ local base = vim.fn.fnamemodify(source, ":p:h:h:h") -- :p (absoluto), :h (sobe 1: skills), :h (sobe 1: multi_context), :h (sobe 1: lua) -- Verifica se realmente estamos em uma estrutura lua/multi_context para evitar caminhos loucos if vim.fn.fnamemodify(base, ":t") == "lua" then return vim.fn.fnamemodify(base, ":h") -- Retorna a raiz do plugin (pai de lua) end return base end M.get_skill_doc = function(skill_name) local base_path = get_plugin_base_path() if not base_path then return nil end -- Caminho absoluto: {raiz}/lua/multi_context/skills/docs/{skill}.md local skill_file = vim.fn.join({ base_path, "lua", "multi_context", "skills", "docs", skill_name .. ".md" }, "/") -- Fallback para caminho relativo caso a lógica absoluta falhe em alguns setups muito específicos if vim.fn.filereadable(skill_file) == 0 then local curr_file = debug.getinfo(1, "S").source:sub(2) local fallback_dir = vim.fn.fnamemodify(curr_file, ":h") .. "/docs/" skill_file = fallback_dir .. skill_name .. ".md" end if vim.fn.filereadable(skill_file) == 1 then return table.concat(vim.fn.readfile(skill_file), "\n") end return nil end M.build_manual_for_skills = function(skills_array) if not skills_array or #skills_array == 0 then return "" end local manual = [[ === FERRAMENTAS DO SISTEMA (SYSTEM TOOLS) === Você é um Agente Autônomo rodando nativamente dentro do editor Neovim do usuário. REGRA ABSOLUTA DE FORMATO: Para invocar uma ferramenta, você DEVE usar ESTRITAMENTE o formato de tags XML exemplificado abaixo. É ESTRITAMENTE PROIBIDO usar formato JSON. NÃO ENVOLVA os argumentos com tags extras. === SMART PUSH (AUTO-LSP) === Sempre que usar ferramentas de edição, a geração de texto será pausada e o sistema injetará automaticamente os erros sintáticos (LSP). NÃO CHAME get_diagnostics logo após editar, leia a resposta do sistema. === HABILIDADES ATIVAS (SKILLS) === Você tem permissão exclusiva para usar apenas as ferramentas abaixo: ]] for _, skill in ipairs(skills_array) do local doc = M.get_skill_doc(skill) if doc then manual = manual .. "\n" .. doc .. "\n" end end return manual end return M 
